+<script>
+  function initLightbox() {
+    let lightbox = document.getElementById("dreammade-lightbox");
+    if (!lightbox) {
+      lightbox = document.createElement("div");
+      lightbox.id = "dreammade-lightbox";
+      lightbox.className = "lightbox-overlay";
+      lightbox.setAttribute("hidden", "true");
+      lightbox.innerHTML = `
+        <button class="lightbox-close" aria-label="Close gallery">&times;</button>
+        <img class="lightbox-image" src="" alt="" />
+      `;
+      document.body.appendChild(lightbox);
+
+      const closeLightbox = () => {
+        if (!lightbox) return;
+        lightbox.classList.remove("active");
+        setTimeout(() => {
+          if (!lightbox?.classList.contains("active")) {
+            lightbox?.setAttribute("hidden", "true");
+          }
+        }, 300);
+      };
+
+      lightbox.querySelector(".lightbox-close")?.addEventListener("click", closeLightbox);
+      lightbox.addEventListener("click", (e) => {
+        if (e.target === lightbox) closeLightbox();
+      });
+
+      window.addEventListener("keydown", (e) => {
+        if (e.key === "Escape" && lightbox?.classList.contains("active")) {
+          closeLightbox();
+        }
+      });
+    }
+
+    const images = document.querySelectorAll("[data-poster-gallery-item] img");
+    images.forEach((imgEl) => {
+      imgEl.addEventListener("click", (e) => {
+        const target = e.currentTarget as HTMLImageElement;
+        const src = target.getAttribute("src");
+        const alt = target.getAttribute("alt") || "";
+        if (!src || !lightbox) return;
+
+        const lightboxImg = lightbox.querySelector(".lightbox-image") as HTMLImageElement;
+        if (lightboxImg) {
+          lightboxImg.src = src;
+          lightboxImg.alt = alt;
+        }
+        lightbox.removeAttribute("hidden");
+        // Force reflow
+        lightbox.offsetHeight;
+        lightbox.classList.add("active");
+      });
+    });
+  }
+
+  initLightbox();
+  document.addEventListener("astro:page-load", initLightbox);
+  window.addEventListener("dreammade:poster-gallery-visible", initLightbox);
+</script>

